  // Get all table rows in the institutions view to find 13D/13G rows
  const body = document.getElementById('company-profile-body');
  if (!body) return 'no body';
  const tables = body.querySelectorAll('table');
  const info = [];
  tables.forEach((t, i) => {
    const rows = t.querySelectorAll('tbody tr');
    const rowInfo = [];
    rows.forEach(r => {
      rowInfo.push({
        text: r.textContent.trim().substring(0, 80),
        classes: r.className,
        borderLeft: window.getComputedStyle(r).borderLeftColor
      });
    });
    info.push({ tableIndex: i, headerText: t.querySelector('thead')?.textContent?.trim(), rowCount: rows.length, rows: rowInfo });
  });
  return info;
}

